import java.util.*;
import java.util.stream.*;

public class Main {
    static final class Box<T> { private final T value; Box(T value) { this.value = value; } T value() { return value; } }

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        Box<String> box = new Box<>(input.next());
        System.out.println(box.value());
    }
}
